<script>export let label='',variant='primary',size='base',disabled=false,loading=false,iconOnly=false,type='button';let n=0;function activate(e){if(disabled||loading){e.preventDefault();return}n++}</script><button {type} class="kumo-button {variant} {size}" disabled={disabled||loading} aria-disabled={disabled||undefined} aria-busy={loading||undefined} aria-label={iconOnly?label:undefined} onclick={activate}>{loading?'Loading…':iconOnly?'+':label}{#if n}<span class="count"> {n}</span>{/if}</button>